+/**
+ * Retry with Exponential Backoff
+ *
+ * Production-ready retry logic with jitter, max retries, and error filtering.
+ *
+ * @module v3/shared/resilience/retry
+ */
+
+/**
+ * Retry options
+ */
+export interface RetryOptions {
+  /** Maximum number of retry attempts (default: 3) */
+  maxAttempts: number;
+
+  /** Initial delay in milliseconds (default: 100) */
+  initialDelay: number;
+
+  /** Maximum delay in milliseconds (default: 10000) */
+  maxDelay: number;
+
+  /** Backoff multiplier (default: 2) */
+  backoffMultiplier: number;
+
+  /** Jitter factor 0-1 to randomize delays (default: 0.1) */
+  jitter: number;
+
+  /** Timeout for each attempt in milliseconds (default: 30000) */
+  timeout: number;
+
+  /** Errors that should trigger a retry (default: all errors) */
+  retryableErrors?: (error: Error) => boolean;
+
+  /** Callback for each retry attempt */
+  onRetry?: (error: Error, attempt: number, delay: number) => void;
+}
+
+/**
+ * Retry result
+ */
+export interface RetryResult<T> {
+  success: boolean;
+  result?: T;
+  attempts: number;
+  totalTime: number;
+  errors: Error[];
+}
+
+/**
+ * Retry error with attempt history
+ */
+export class RetryError extends Error {
+  constructor(
+    message: string,
+    public readonly attempts: number,
+    public readonly errors: Error[],
+    public readonly totalTime: number
+  ) {
+    super(message);
+    this.name = 'RetryError';
+  }
+}
+
+/**
+ * Default retry options
+ */
+const DEFAULT_OPTIONS: RetryOptions = {
+  maxAttempts: 3,
+  initialDelay: 100,
+  maxDelay: 10000,
+  backoffMultiplier: 2,
+  jitter: 0.1,
+  timeout: 30000,
+};
+
+/**
+ * Retry a function with exponential backoff
+ *
+ * @param fn Function to retry
+ * @param options Retry configuration
+ * @returns Result with success/failure and metadata
+ *
+ * @example
+ * const result = await retry(
+ *   () => fetchData(),
+ *   { maxAttempts: 5, initialDelay: 200 }
+ * );
+ *
+ * if (result.success) {
+ *   console.log('Data:', result.result);
+ * } else {
+ *   console.log('Failed after', result.attempts, 'attempts');
+ * }
+ */
+export async function retry<T>(
+  fn: () => Promise<T>,
+  options: Partial<RetryOptions> = {}
+): Promise<RetryResult<T>> {
+  const opts = { ...DEFAULT_OPTIONS, ...options };
+  const errors: Error[] = [];
+  const startTime = Date.now();
+
+  for (let attempt = 1; attempt <= opts.maxAttempts; attempt++) {
+    try {
+      // Execute with timeout
+      const result = await withTimeout(fn(), opts.timeout, attempt);
+
+      return {
+        success: true,
+        result,
+        attempts: attempt,
+        totalTime: Date.now() - startTime,
+        errors,
+      };
+    } catch (error) {
+      const err = error instanceof Error ? error : new Error(String(error));
